<?php
$pageTitle='Replenishment';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('replenishment');
$pdo=getDB();
$products=$pdo->query('SELECT id,sku,name FROM '.table('products').' ORDER BY name LIMIT 500')->fetchAll();$warehouses=$pdo->query('SELECT id,warehouse_name FROM '.table('warehouses').' ORDER BY warehouse_name')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)$_POST['action'];if($action==='rule'){$code=trim((string)$_POST['rule_code']); if($code===''){$code='RULE-'.date('YmdHis');}$pdo->prepare('INSERT INTO '.table('replenishment_rules').' (rule_code,product_id,warehouse_id,min_qty,max_qty,reorder_qty,status) VALUES (?,?,?,?,?,?,"active")')->execute([$code,(int)$_POST['product_id'],(int)$_POST['warehouse_id'],max(0,(float)$_POST['min_qty']),max(0,(float)$_POST['max_qty']),max(0,(float)$_POST['reorder_qty'])]);flash('success','Replenishment rule created.');}elseif($action==='generate'){$created=createReplenishmentSuggestions($pdo);flash('success','Generated '.$created.' replenishment suggestions.');}elseif($action==='close'){$pdo->prepare('UPDATE '.table('replenishment_suggestions').' SET status="closed",closed_at=NOW() WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Suggestion closed.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'replenishment']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/replenishment.php');}
$rules=$pdo->query('SELECT r.*,p.sku,p.name,w.warehouse_name FROM '.table('replenishment_rules').' r LEFT JOIN '.table('products').' p ON p.id=r.product_id LEFT JOIN '.table('warehouses').' w ON w.id=r.warehouse_id ORDER BY r.created_at DESC LIMIT 100')->fetchAll();
$suggestions=$pdo->query('SELECT s.*,p.sku,p.name,w.warehouse_name FROM '.table('replenishment_suggestions').' s LEFT JOIN '.table('products').' p ON p.id=s.product_id LEFT JOIN '.table('warehouses').' w ON w.id=s.warehouse_id ORDER BY s.created_at DESC LIMIT 150')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Stock Planning</div><h2 class="h4 mb-1">Replenishment</h2><p class="text-secondary mb-0">Define min/max rules and generate reorder suggestions by warehouse.</p></div><form method="post"><input type="hidden" name="action" value="generate"><button class="btn btn-brand">Generate Suggestions</button></form></div><div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="rule"><h2 class="h5 mb-3">Create Rule</h2><input class="form-control mb-2" name="rule_code" placeholder="Rule code"><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?php echo (int)$w['id']; ?>"><?php echo esc($w['warehouse_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="number" step="0.0001" name="min_qty" placeholder="Min qty"><input class="form-control mb-2" type="number" step="0.0001" name="max_qty" placeholder="Max qty"><input class="form-control mb-3" type="number" step="0.0001" name="reorder_qty" placeholder="Reorder qty"><button class="btn btn-outline-primary w-100">Create Rule</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Suggestions</h2><table class="table"><thead><tr><th>Suggestion</th><th>Product</th><th>Warehouse</th><th>Current</th><th>Recommended</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($suggestions as $s): ?><tr><td><strong><?php echo esc($s['suggestion_number']); ?></strong></td><td><?php echo esc($s['sku'].' · '.$s['name']); ?></td><td><?php echo esc($s['warehouse_name']); ?></td><td><?php echo number_format((float)$s['current_qty'],4); ?></td><td><?php echo number_format((float)$s['recommended_qty'],4); ?></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td><td><?php if($s['status']==='open'): ?><form method="post"><input type="hidden" name="action" value="close"><input type="hidden" name="id" value="<?php echo (int)$s['id']; ?>"><button class="btn btn-sm btn-outline-success">Close</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Rules</h2><table class="table"><thead><tr><th>Rule</th><th>Product</th><th>Warehouse</th><th>Min</th><th>Max</th><th>Reorder</th></tr></thead><tbody><?php foreach($rules as $r): ?><tr><td><strong><?php echo esc($r['rule_code']); ?></strong></td><td><?php echo esc($r['sku'].' · '.$r['name']); ?></td><td><?php echo esc($r['warehouse_name']); ?></td><td><?php echo number_format((float)$r['min_qty'],4); ?></td><td><?php echo number_format((float)$r['max_qty'],4); ?></td><td><?php echo number_format((float)$r['reorder_qty'],4); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>